) AS v(candidate_slug, constituency_slug, party_abbrev, nomination_date)
JOIN candidates    c ON c.slug = v.candidate_slug
JOIN constituencies co ON co.slug = v.constituency_slug
LEFT JOIN parties  p ON p.abbreviation = v.party_abbrev
ON CONFLICT (candidate_id, constituency_id, election_year)
  DO UPDATE SET
    party_id = EXCLUDED.party_id,
    is_current_election = TRUE,
    nomination_date = EXCLUDED.nomination_date;

-- ── Update search_index: candidates now include constituency sub_label ──
DROP MATERIALIZED VIEW IF EXISTS search_index;
CREATE MATERIALIZED VIEW search_index AS
SELECT
  'candidate' AS entity_type,
  c.id::TEXT AS entity_id,
  c.slug,
  c.full_name AS label,
  c.full_name_ta AS label_ta,
  co.name AS sub_label,
  to_tsvector('simple', c.full_name) AS tsv
FROM candidates c
LEFT JOIN election_contests ec ON ec.candidate_id = c.id AND ec.is_current_election = true
LEFT JOIN constituencies co ON co.id = ec.constituency_id
UNION ALL
SELECT
  'constituency',
  co.id::TEXT,
  co.slug,
  co.name,
  co.name_ta,
  d.name,
  to_tsvector('simple', co.name || ' ' || d.name)
FROM constituencies co
JOIN districts d ON d.id = co.district_id;
CREATE INDEX idx_search_tsv ON search_index USING gin(tsv);
